"""应用 Release 信息与 GitHub latest / releases 列表（respx）。"""import refrom unittest.mock import patchimport httpximport pytestimport respxfrom fastapi import FastAPIfrom httpx import ASGITransport, AsyncClientfrom app.api import app_release, depsfrom app.utils import github_release@pytest.fixture(autouse=True)def _clear_gh_cache():    github_release.clear_github_release_cache()    yield    github_release.clear_github_release_cache()@pytest.mark.asyncioasync def test_release_info_without_login():    app = FastAPI()    app.include_router(app_release.router)    async def _anon():        return None    app.dependency_overrides[deps.get_current_user_optional] = _anon    transport = ASGITransport(app=app)    async with AsyncClient(transport=transport, base_url="http://test") as ac:        r = await ac.get("/api/app/release-info")    assert r.status_code == 200    body = r.json()    assert body["current_version"]    assert body["current_version_display"].startswith("v")    assert body["remote_loaded"] is False    assert body["latest_version"] is None    assert body["newer_releases"] == []def _mock_latest():    return httpx.Response(        200,        json={            "tag_name": "v9.0.0",            "html_url": "https://github.com/SanaeMio/Bangumi-syncer/releases/tag/v9.0.0",            "name": "Nine",            "body": "## Notes\nhello",            "published_at": "2026-01-01T12:00:00Z",        },        headers={"ETag": '"abc"'},    )def _mock_releases_page(json_body):    return httpx.Response(200, json=json_body)@pytest.mark.asyncio@respx.mockasync def test_release_info_with_login_and_github():    respx.get(github_release.GITHUB_LATEST_URL).mock(return_value=_mock_latest())    respx.get(url=re.compile(r".*/Bangumi-syncer/releases\?.*")).mock(        return_value=_mock_releases_page([])    )    app = FastAPI()    app.include_router(app_release.router)    async def _user():        return {"username": "admin"}    app.dependency_overrides[deps.get_current_user_optional] = _user    transport = ASGITransport(app=app)    async with AsyncClient(transport=transport, base_url="http://test") as ac:        with patch("app.api.app_release.get_version", return_value="1.0.0"):            r = await ac.get("/api/app/release-info")    assert r.status_code == 200    body = r.json()    assert body["remote_loaded"] is True    assert body["current_version_display"] == "v1.0.0"    assert body["latest_version"] == "9.0.0"    assert body["latest_version_display"] == "v9.0.0"    assert body["update_available"] is True    assert body["release_url"].endswith("v9.0.0")    assert body["updates_behind"] == 1    assert len(body["newer_releases"]) == 1    nr0 = body["newer_releases"][0]    assert nr0["semver"] == "9.0.0"    assert "hello" in (nr0.get("body_html") or "")    assert "<" in (nr0.get("body_html") or "")@pytest.mark.asyncio@respx.mockasync def test_release_info_multiple_versions():    respx.get(github_release.GITHUB_LATEST_URL).mock(return_value=_mock_latest())    rel_json = [        {            "tag_name": "v9.0.0",            "draft": False,            "html_url": "https://github.com/SanaeMio/Bangumi-syncer/releases/tag/v9.0.0",            "name": "Nine",            "body": "## Nine\nlast",            "published_at": "2026-03-01T00:00:00Z",        },        {            "tag_name": "v3.0.0",            "draft": False,            "html_url": "https://github.com/SanaeMio/Bangumi-syncer/releases/tag/v3.0.0",            "name": "Three",            "body": "## Three\nmid",            "published_at": "2026-02-01T00:00:00Z",        },        {            "tag_name": "v2.0.0",            "draft": False,            "html_url": "https://github.com/SanaeMio/Bangumi-syncer/releases/tag/v2.0.0",            "name": "Two",            "body": "## Two\nold",            "published_at": "2026-01-15T00:00:00Z",        },    ]    respx.get(url=re.compile(r".*/Bangumi-syncer/releases\?.*")).mock(        return_value=_mock_releases_page(rel_json)    )    app = FastAPI()    app.include_router(app_release.router)    async def _user():        return {"username": "admin"}    app.dependency_overrides[deps.get_current_user_optional] = _user    transport = ASGITransport(app=app)    async with AsyncClient(transport=transport, base_url="http://test") as ac:        with patch("app.api.app_release.get_version", return_value="1.0.0"):            r = await ac.get("/api/app/release-info")    assert r.status_code == 200    body = r.json()    assert body["updates_behind"] == 3    sems = [x["semver"] for x in body["newer_releases"]]    assert sems == ["9.0.0", "3.0.0", "2.0.0"]    assert "mid" in body["newer_releases"][1]["body_html"]@pytest.mark.asyncio@respx.mockasync def test_release_info_releases_list_error_still_shows_latest():    respx.get(github_release.GITHUB_LATEST_URL).mock(return_value=_mock_latest())    respx.get(url=re.compile(r".*/Bangumi-syncer/releases\?.*")).mock(        return_value=httpx.Response(500)    )    app = FastAPI()    app.include_router(app_release.router)    async def _user():        return {"username": "admin"}    app.dependency_overrides[deps.get_current_user_optional] = _user    transport = ASGITransport(app=app)    async with AsyncClient(transport=transport, base_url="http://test") as ac:        with patch("app.api.app_release.get_version", return_value="1.0.0"):            r = await ac.get("/api/app/release-info")    assert r.status_code == 200    body = r.json()    assert body["releases_fetch_error"]    assert body["updates_behind"] == 1    assert len(body["newer_releases"]) == 1    assert body["newer_releases"][0]["semver"] == "9.0.0"@pytest.mark.asyncio@respx.mockasync def test_release_info_github_error():    respx.get(github_release.GITHUB_LATEST_URL).mock(return_value=httpx.Response(403))    app = FastAPI()    app.include_router(app_release.router)    async def _user():        return {"username": "admin"}    app.dependency_overrides[deps.get_current_user_optional] = _user    transport = ASGITransport(app=app)    async with AsyncClient(transport=transport, base_url="http://test") as ac:        with patch("app.api.app_release.get_version", return_value="3.0.0"):            r = await ac.get("/api/app/release-info")    assert r.status_code == 200    body = r.json()    assert body["github_error"]    assert body["current_version_display"] == "v3.0.0"    assert body["newer_releases"] == []